const list = $input.all();
const groupedData = {};

list.forEach(item => {
  const key = `${item.json.sessionid}_${item.json.email}`;
  if (!groupedData[key]) {
    groupedData[key] = [];
  }
  groupedData[key].push(item.json);
});

return { groupedData };


